// Get the URL from the previous node (adjust the field name if needed)
const url = $input.first().json['Search Results URL'];

// Normalize
const normalizedUrl = url.toLowerCase();

let linkedinType = "unknown";

if (normalizedUrl.includes("linkedin.com/sales/")) {
  linkedinType = "sales_navigator";
} 
else if (normalizedUrl.includes("linkedin.com/talent/")) {
  linkedinType = "recruiter";
} 
else if (normalizedUrl.includes("linkedin.com/search/")) {
  linkedinType = "basic";
}

// Return value for Switch node
return [
  {
    json: {
      linkedinType: linkedinType,
      originalUrl: url
    }
  }
];

let linkedinType = $('Code in JavaScript').first().json.linkedinType;
let runId = "";

// Switch to assign Run ID per type
switch (linkedinType) {
  case "basic":
    runId = $input.first().json.data.toolRunId;
    break;

  case "sales_navigator":
    runId = $input.first().json.data.toolRunId;
    break;

  case "recruiter":
    runId = $input.first().json.data.toolRunId;
    break;

  default:
    runId = "RUN_UNKNOWN_001";
}

// Return everything for downstream nodes
return [
  {
    json: {
      sourcegeek: {
        linkedinType,
        runId
      }
    }
  }
];

// n8n Code node (Run once for each item)

// Your input is an array of items; in n8n Code node you usually get them via $input.all()
const items = $input.all();

const output = [];

for (const item of items) {
  const data = item.json?.data || {};
  const contacts = Array.isArray(data.contacts) ? data.contacts : [];

  const runId = data.toolRunId || "";
  const searchId = data.id || "";
  const status = item.json?.status || "";

  for (const c of contacts) {
    output.push({
      json: {
        // run context (useful for traceability)
        toolRunId: runId,
        searchId,
        status,

        // contact fields (map these to your sheet columns)
        contactId: c.id || "",
        createdAt: c.createdAt || "",
        updatedAt: c.updatedAt || "",
        firstName: c.firstName || "",
        lastName: c.lastName || "",
        email: c.email || "",
        phone: c.phone || "",
        description: c.description || "",
        profileImageUrl: c.profileImageUrl || "",
        linkedinId: c.linkedinId || "",
        linkedinUsername: c.linkedinUsername || "",
        linkedinProfileUrl: c.linkedinUsername ? `https://www.linkedin.com/in/${c.linkedinUsername}` : "",
        location: c.location || "",
        jobTitle: c.jobTitle || "",
        companyName: c.companyName || "",
        companyIndustry: c.companyIndustry || "",
        companyLocation: c.companyLocation || "",
      }
    });
  }
}

return output;
